#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Instruction opcode definitions
#define OP_LOAD 1
#define OP_STORE 2
#define OP_ADD 3
#define OP_SUB 4
#define OP_MUL 5
#define OP_MOV 6
#define OP_CMP 7
#define OP_BRANCH 8
#define OP_BZ 9
#define OP_BNZ 10
#define OP_CALL 11
#define OP_RETURN 12
#define OP_HALT 13
#define OP_IN 14
#define OP_OUT 15

// Operand types
#define OP_TYPE_REG 1
#define OP_TYPE_IMM 2
#define OP_TYPE_MEM 3
#define OP_TYPE_LABEL 4

// CPU State Structure
typedef struct {
 int pc; // Program Counter
 int ir; // Instruction Register
 int acc; // Accumulator
 int registers[8]; // General purpose registers R0-R7
 int flags; // Condition flags (bit 0: Z, bit 1: N, bit 2: C, bit 3: V)
 int running; // CPU running status
} CPU;

// Instruction Structure
typedef struct {
 int opcode;
 int op1_type, op1_val;
 int op2_type, op2_val;
 int op3_type, op3_val;
} Instruction;

// Memory
#define MEMORY_SIZE 256
int memory[MEMORY_SIZE];
int stack[64];
int sp = -1; // Stack pointer

// Initialize CPU
void initCPU(CPU *cpu) {
 cpu->pc = 0;
 cpu->ir = 0;
 cpu->acc = 0;
 cpu->flags = 0;
 cpu->running = 1;
 memset(cpu->registers, 0, sizeof(cpu->registers));
 sp = -1;
}

// Stack operations
void push(int value) {
 if (sp < 63) {
 stack[++sp] = value;
 }
}

int pop() {
 if (sp >= 0) {
 return stack[sp--];
 }
 return -1;
}

// Update condition flags
void updateFlags(CPU *cpu, int result) {
 // Clear flags
 cpu->flags = 0;

 // Zero flag
 if (result == 0) cpu->flags |= 0x01;
 // Negative flag
 if (result < 0) cpu->flags |= 0x02;
 // Carry flag (simplified)
 if (result > 32767 || result < -32768) cpu->flags |= 0x04;
 // Overflow flag
 if ((result > 32767) || (result < -32768)) cpu->flags |= 0x08;
}

// Get value from operand
int getValue(CPU *cpu, int type, int val) {
 switch(type) {
 case OP_TYPE_REG: return cpu->registers[val];
 case OP_TYPE_IMM: return val;
 case OP_TYPE_MEM: return memory[val];
 default: return 0;
 }
}

// Store result to operand
void setValue(CPU *cpu, int type, int val, int result) {
 switch(type) {
 case OP_TYPE_REG:
 cpu->registers[val] = result;
 break;
 case OP_TYPE_MEM:
 memory[val] = result;
 break;
 }
}

// Fetch instruction from memory
Instruction* fetch(CPU *cpu) {
 int instrWord = memory[cpu->pc++];
 static Instruction instr;

 // Decode instruction word (simplified encoding)
 // Format: [opcode (8 bits)][op1_type][op1_val][op2_type][op2_val][op3_type][op3_val]
 instr.opcode = (instrWord >> 24) & 0xFF;
 instr.op1_type = (instrWord >> 20) & 0xF;
 instr.op1_val = (instrWord >> 16) & 0xF;
 instr.op2_type = (instrWord >> 12) & 0xF;
 instr.op2_val = (instrWord >> 8) & 0xF;
 instr.op3_type = (instrWord >> 4) & 0xF;
 instr.op3_val = instrWord & 0xF;

 return &instr;
}

// Execute instruction
void execute(CPU *cpu, Instruction *instr) {
 int val1, val2, result;

 switch(instr->opcode) {
 case OP_MOV:
 val1 = getValue(cpu, instr->op2_type, instr->op2_val);
 setValue(cpu, instr->op1_type, instr->op1_val, val1);
 break;

 case OP_ADD:
 val1 = getValue(cpu, instr->op2_type, instr->op2_val);
 val2 = getValue(cpu, instr->op3_type, instr->op3_val);
 result = val1 + val2;
 setValue(cpu, instr->op1_type, instr->op1_val, result);
 updateFlags(cpu, result);
 break;

 case OP_SUB:
 val1 = getValue(cpu, instr->op2_type, instr->op2_val);
 val2 = getValue(cpu, instr->op3_type, instr->op3_val);
 result = val1 - val2;
 setValue(cpu, instr->op1_type, instr->op1_val, result);
 updateFlags(cpu, result);
 break;

 case OP_MUL:
 val1 = getValue(cpu, instr->op2_type, instr->op2_val);
 val2 = getValue(cpu, instr->op3_type, instr->op3_val);
 result = val1 * val2;
 setValue(cpu, instr->op1_type, instr->op1_val, result);
 updateFlags(cpu, result);
 break;

 case OP_LOAD:
 val1 = getValue(cpu, instr->op2_type, instr->op2_val);
 cpu->acc = val1;
 setValue(cpu, instr->op1_type, instr->op1_val, val1);
 break;

 case OP_STORE:
 val1 = getValue(cpu, instr->op2_type, instr->op2_val);
 setValue(cpu, instr->op1_type, instr->op1_val, val1);
 break;

 case OP_CMP:
 val1 = getValue(cpu, instr->op1_type, instr->op1_val);
 val2 = getValue(cpu, instr->op2_type, instr->op2_val);
 result = val1 - val2;
 updateFlags(cpu, result);
 break;

 case OP_BRANCH:
 cpu->pc = instr->op1_val;
 break;

 case OP_BZ: // Branch if Zero
 if (cpu->flags & 0x01) {
 cpu->pc = instr->op1_val;
 }
 break;

 case OP_BNZ: // Branch if Not Zero
 if (!(cpu->flags & 0x01)) {
 cpu->pc = instr->op1_val;
 }
 break;

 case OP_CALL:
 push(cpu->pc); // Save return address
 cpu->pc = instr->op1_val; // Jump to subroutine
 break;

 case OP_RETURN:
 cpu->pc = pop(); // Restore return address
 break;

 case OP_HALT:
 cpu->running = 0;
 break;

 case OP_IN:
 printf("Input: ");
 scanf("%d", &val1);
 setValue(cpu, instr->op1_type, instr->op1_val, val1);
 break;

 case OP_OUT:
 val1 = getValue(cpu, instr->op1_type, instr->op1_val);
 printf("Output: %d\n", val1);
 break;
 }
}

// Simpler instruction loading for demo
void loadInstruction(int addr, int opcode, int r1, int r2, int r3) {
 // Simplified encoding for demo
 // Using register direct addressing
 memory[addr] = (opcode << 24) | (OP_TYPE_REG << 20) | (r1 << 16) |
 (OP_TYPE_REG << 12) | (r2 << 8) | (OP_TYPE_REG << 4) | r3;
}

// Print CPU state
void dumpState(CPU *cpu) {
 printf("PC=%d ACC=%d Flags=%d | ", cpu->pc, cpu->acc, cpu->flags);
 printf("R0=%d R1=%d R2=%d R3=%d R4=%d\n", 
 cpu->registers[0], cpu->registers[1], cpu->registers[2], 
 cpu->registers[3], cpu->registers[4]);
}

int main() {
 CPU cpu;
 initCPU(&cpu);

 // Load a simple program: Calculate 5 * 4 = 20
 // R0 = 5, R1 = 4, R2 = R0 * R1
 // Using immediate values from memory
 memory[10] = 5; // Constant 5 at address 10
 memory[11] = 4; // Constant 4 at address 11

 // Load R0, 5
 memory[0] = (OP_LOAD << 24) | (OP_TYPE_REG << 20) | (0 << 16) |
 (OP_TYPE_MEM << 12) | (10 << 8);

 // Load R1, 4 
 memory[1] = (OP_LOAD << 24) | (OP_TYPE_REG << 20) | (1 << 16) |
 (OP_TYPE_MEM << 12) | (11 << 8);

 // MOV R2, R0 (copy R0 to R2 first)
 memory[2] = (OP_MOV << 24) | (OP_TYPE_REG << 20) | (2 << 16) |
 (OP_TYPE_REG << 12) | (0 << 8);

 // Loop: CMP R2, R1
 memory[3] = (OP_CMP << 24) | (OP_TYPE_REG << 20) | (2 << 16) |
 (OP_TYPE_REG << 12) | (1 << 8);

 // BZ 8 (exit loop if equal)
 memory[4] = (OP_BZ << 24) | (OP_TYPE_IMM << 20) | (8 << 16);

 // ADD R0, R0, R1 (R0 = R0 + R1)
 memory[5] = (OP_ADD << 24) | (OP_TYPE_REG << 20) | (0 << 16) |
 (OP_TYPE_REG << 12) | (0 << 8) | (OP_TYPE_REG << 4) | (1);

 // BRANCH 3 (go back to loop)
 memory[6] = (OP_BRANCH << 24) | (OP_TYPE_IMM << 20) | (3 << 16);

 // HALT
 memory[7] = (OP_HALT << 24);

 // OUT R0 (display result)
 memory[8] = (OP_OUT << 24) | (OP_TYPE_REG << 20) | (0 << 16);

 // HALT
 memory[9] = (OP_HALT << 24);

 printf("=== CPU Instruction Execution Demo ===\n");
 printf("Program: Calculate 5 * 4\n\n");

 // Fetch-Execute Cycle
 while (cpu.running) {
 printf("Step %d: ", cpu.pc);
 Instruction *instr = fetch(&cpu);
 execute(cpu, instr);
 dumpState(&cpu);
 }

 printf("\nFinal Result in R0: %d (Expected: 20)\n", cpu.registers[0]);

 return 0;
}
